import os
from datetime import datetime

import questionary
import yaml


PARTITION_TEMPLATE = """\
                {{
                    'name': '{pname}',
                    'descr': '{ptype} partition',
                    'scheduler': '{scheduler}',
                    'launcher': '{launcher}',
                    'environs': ['gnu'],
                }},
"""

SYSTEM_CONFIG_TEMPLATE = """\
# ReFrame site configuration for {sysname}
# Generated by continusbench add-system on {generated_at}

site_configuration = {{
    'systems': [
        {{
            'name': '{sysname}',
            'descr': '{description}',
            'hostnames': ['.*'],
            'modules_system': 'spack',
            'stagedir': '{stagedir}',
            'outputdir': '{outputdir}',
            'partitions': [
{partitions}
            ],
        }},
    ],
}}
"""


class SystemGenerator:
    def __init__(self, config_dir=None, pseudo_cluster_dir=None):
        self.config_dir = config_dir or os.path.join(
            os.path.dirname(__file__), '..', '..', 'config', 'systems'
        )
        os.makedirs(self.config_dir, exist_ok=True)

    def interactive_onboard(self):
        name = questionary.text("System name (e.g., supermuc, paramrudra):").ask()
        if not name:
            return None

        hostname = questionary.text("Login hostname (or empty for local):").ask() or ""
        description = questionary.text("Short description:").ask() or ""

        default_stagedir = "/scratch/$USER/reframe/stage"
        default_outputdir = "/scratch/$USER/reframe/output"
        stagedir = questionary.text(
            "Stage directory (scratch for build/test staging):",
            default=default_stagedir,
        ).ask() or default_stagedir
        outputdir = questionary.text(
            "Output directory (scratch for test outputs):",
            default=default_outputdir,
        ).ask() or default_outputdir

        partitions = []
        while True:
            pname = questionary.text("Partition name (leave empty to finish):").ask()
            if not pname:
                break
            ptype = questionary.select(
                f"Partition '{pname}' type:",
                choices=["cpu", "gpu", "hm", "login"],
            ).ask()
            scheduler = questionary.select(
                f"Scheduler for '{pname}':",
                choices=["slurm", "pbs", "local"],
            ).ask()
            partitions.append({"name": pname, "type": ptype, "scheduler": scheduler})

        if not partitions:
            partitions.append({"name": "default", "type": "cpu", "scheduler": "local"})

        config = {
            "name": name,
            "hostname": hostname,
            "description": description,
            "generated_at": datetime.now().isoformat(),
            "stagedir": stagedir,
            "outputdir": outputdir,
            "partitions": partitions,
        }

        # Write YAML metadata
        yaml_path = os.path.join(self.config_dir, f"{name}.yaml")
        with open(yaml_path, "w") as f:
            yaml.dump(config, f, default_flow_style=False, sort_keys=False)

        # Generate ReFrame settings.py alongside it
        self._generate_reframe_config(name, description, partitions,
                                      stagedir, outputdir)

        return yaml_path

    def _generate_reframe_config(self, sysname, description,
                                  partitions, stagedir, outputdir):
        partition_entries = []
        for p in partitions:
            launcher = "local" if p["scheduler"] == "local" else "mpirun"
            partition_entries.append(PARTITION_TEMPLATE.format(
                pname=p["name"], ptype=p["type"],
                scheduler=p["scheduler"], launcher=launcher,
            ))
        partitions_text = "".join(partition_entries)

        config_text = SYSTEM_CONFIG_TEMPLATE.format(
            sysname=sysname,
            description=description,
            generated_at=datetime.now().isoformat(),
            stagedir=stagedir, outputdir=outputdir,
            partitions=partitions_text,
        )

        reframe_path = os.path.join(self.config_dir, f"{name}.py")
        with open(reframe_path, "w") as f:
            f.write(config_text)

    def load_system(self, name):
        filepath = os.path.join(self.config_dir, f"{name}.yaml")
        if not os.path.exists(filepath):
            return None
        with open(filepath) as f:
            return yaml.safe_load(f)
